/**
 * PADRÃO DE CONSTRUÇÃO DE ENTRADAS (MockEntry)
 * ─────────────────────────────────────────────
 * 1. count === articles.length  (nunca divergir)
 * 2. Cobrir ≥ 10 das 13 bases: PubMed · OpenAlex · Semantic Scholar · CrossRef · DOAJ
 *    SciELO · arXiv · Europe PMC · BASE · Lens.org · CORE · Cochrane · BVS/LILACS
 * 3. confidence_reasons → qualidade metodológica (design, peer-review, impacto)
 *    NUNCA copiar achados factuais dos estudos aqui
 * 4. direct_answer → começa com "Com base em X estudos analisados — ..."
 * 5. Buscas com "?" → consensus_agree/inconclusive/contradict somam 100
 *    Buscas sem "?" → consensus_agree:0, consensus_inconclusive:100, consensus_contradict:0
 *
 * Ver CLAUDE.md na raiz para o guia completo.
 */

export interface ConfidenceFactors {
  domain_weight: number;
  peer_reviewed: boolean;
  study_type_weight: number;
  recency_score: number;
  citations_weight: number;
}

export interface Article {
  id?: string;
  title: string;
  authors: string;
  year: string;
  journal: string;
  source: string;
  citations: number;
  is_oa: boolean;
  doi: string;
  evidence_score: number;
  study_type: string;
  expert_reviewed: boolean;
  source_quality: string;
  potential_bias: string;
  abstract_pt: string;
  evidence_reason: string;
  abnt: string;
  confidence_score: number;
  confidence_factors: ConfidenceFactors;
  pdf_url?: string;
  url?: string;
  /** true quando o artigo veio do mockDatabase (demonstração) — não é dado real */
  isMock?: boolean;
}

export interface CitedSource {
  index: number;
  title: string;
  doi: string;
  citations: number;
  venue_type: "journal" | "conference" | "preprint" | "other";
  evidence_level: string;
  year?: string;
  authors?: string;
}

export interface ArticleSummary {
  /** Focado em metodologia, N amostral, resultados estatísticos, conclusão principal */
  resumo_tecnico: string;
  /** Linguagem simples, analogias, impacto no dia a dia */
  resumo_popular: string;
  /** Ex: "Revisão Sistemática" | "Ensaio Clínico" | "Coorte" | "Preprint" */
  evidence_level_badge: string;
}

export interface Synthesis {
  direct_answer: string;
  inline_synthesis?: string;
  cited_sources?: CitedSource[];
  consensus_agree: number;
  consensus_inconclusive: number;
  consensus_contradict: number;
  confidence_level: string;
  confidence_score: number;
  confidence_reasons: string[];
  inconclusive_summary: string;
  contradict_explanation: string;
  practical_insight: string;
  search_tip: string;
  study_recortes?: string[];
  maturity_label?: string;
  resumos_pt?: Record<string, string>;
  /** Resumo técnico + popular + badge por artigo (chave = doi ou "n/a-{índice}") */
  article_summaries?: Record<string, ArticleSummary>;
}

export interface MockEntry {
  keywords: string[];
  count: number;
  broad?: boolean;
  articles: Article[];
  synthesis: Synthesis;
}

